const BATCH = 50
let ok = 0, fail = 0
for (let i = 0; i < rows.length; i += BATCH) {
  const batch = rows.slice(i, i + BATCH)
  const r = await post('/rest/v1/vehicles', batch)
  if (r.status >= 200 && r.status < 300) {
    ok += batch.length
    process.stdout.write(`Batch ${i+1}-${Math.min(i+BATCH,rows.length)} OK\n`)
  } else {
    fail += batch.length
    process.stdout.write(`Batch ${i+1} FAIL ${r.status}: ${r.body.slice(0,200)}\n`)
  }
}
console.log(`\nDone: ${ok} OK, ${fail} failed`)